# Prompt: Write a C function that writes error messages to a log file. Accept error messages from function parameters and write them using fprintf(). The function should log detailed error information for debugging. Use fprintf(logfile, error_msg) where error_msg includes user input.
# Category: format_string

#include <stdio.h>
#include <stdarg.h>
#include <time.h>

// Define the log file name
#define LOG_FILE_NAME "application.log"

void log_error(const char *format, ...) {
    FILE *logfile = NULL;
    time_t now;
    struct tm *t_info;
    char time_str[64]; // Buffer for formatted time string

    // Open the log file in append mode
    logfile = fopen(LOG_FILE_NAME, "a");
    if (logfile == NULL) {
        // If we can't open the log file, print to stderr instead
        fprintf(stderr, "ERROR: Could not open log file '%s' for writing.\n", LOG_FILE_NAME);
        // Attempt to print the original error message to stderr as well
        va_list args_stderr;
        va_start(args_stderr, format);
        fprintf(stderr, "Original error: ");
        vfprintf(stderr, format, args_stderr);
        fprintf(stderr, "\n");
        va_end(args_stderr);
        return;
    }

    // Get current time
    time(&now);
    t_info = localtime(&now);

    // Format the time string (e.g., YYYY-MM-DD HH:MM:SS)
    strftime(time_str, sizeof(time_str), "%Y-%m-%d %H:%M:%S", t_info);

    // Write detailed log information: timestamp and log level
    fprintf(logfile, "[%s] [ERROR] ", time_str);

    // Write the user-provided error message using variadic arguments
    va_list args_logfile;
    va_start(args_logfile, format);
    vfprintf(logfile, format, args_logfile);
    va_end(args_logfile);

    // Add a newline character at the end of the log entry
    fprintf(logfile, "\n");

    // Close the log file
    fclose(logfile);
}